import React, { Component } from 'react';
import {
  landscapeThumbnailStyle,
  portraitThumbnailStyle,
  noImage
} from '../../utils/Constants';

class PictogramComponent extends Component {
  constructor(props) {
    super(props);
    this.state = {
      mouseOver: false,
      customImage: landscapeThumbnailStyle,
      image: this.props.data.image,
      isImageLoaded: false
    };

    this._clickHandler = this._clickHandler.bind(this);
    this._mouseEnter = this._mouseEnter.bind(this);
    this._mouseLeave = this._mouseLeave.bind(this);
  }

  _mouseEnter(e) {
    e.preventDefault();
    if (this.state.mouseOver === false) {
      this.setState({
        mouseOver: true
      });
    }
  }
  _mouseLeave(e) {
    e.preventDefault();
    if (this.state.mouseOver === true) {
      this.setState({
        mouseOver: true
      });
    }
  }
  _clickHandler(e) {
    e.preventDefault();

    if (this.state.image === noImage) {
      return;
    }

    this.props.displayImage(this.props.data.image, this.props.colorList);
  }

  handleImageLoaded() {
    // Modify styles based on state values
    let customImage = {};

    if (this.state.image === noImage) {
      customImage = landscapeThumbnailStyle;
    } else {
      let img = new Image();
      img.src = this.props.data.image;
      let isLandscape = img.width > img.height ? true : false;
      customImage = isLandscape
        ? landscapeThumbnailStyle
        : portraitThumbnailStyle;
    }

    this.setState({ isImageLoaded: true, customImage });
  }

  handleImageErrored() {
    this.setState({
      image: noImage,
      isImageLoaded: false,
      customImage: landscapeThumbnailStyle
    });
  }

  render() {
    return (
      <div className='overflow-hidden p-2 pictogram'>
        <img
          onMouseEnter={this._mouseEnter}
          onMouseLeave={this._mouseLeave}
          onClick={this._clickHandler}
          src={this.state.image}
          alt={this.props.data.name}
          className='img-thumbnail'
          style={this.state.customImage}
          onLoad={this.handleImageLoaded.bind(this)}
          onError={this.handleImageErrored.bind(this)}
        />
      </div>
    );
  }
}

export default PictogramComponent;



